#!/usr/bin/env node
// Generate every tool's rule files from the single source of truth: rules/*.md
//
// rules/ is vendor-neutral and the ONLY place you edit. No AI tool owns the
// rules. Each tool reads a different location and most cannot import an external
// file, so the rule text is generated into each location from rules/. Hand
// editing any generated file is banned (it would drift): see
// rules/dry-reuse-no-duplication.md and rules/no-fallbacks-no-legacy.md.
//
// Generated targets:
//   .kiro/steering/*.md            (Kiro: native, one file each)
//   CLAUDE.md                      (Claude Code: @import of rules/*.md)
//   .cursor/rules/area-code.mdc    (Cursor: always-apply, combined)
//   .windsurf/rules/area-code.md   (Windsurf: always-on, combined)
//   .github/copilot-instructions.md(Copilot: combined)
//
// Usage:
//   node scripts/sync-ai-rules.mjs          # write the generated files
//   node scripts/sync-ai-rules.mjs --check  # exit 1 if any generated file is stale
//
import {
  readFileSync,
  writeFileSync,
  readdirSync,
  mkdirSync,
  existsSync,
  rmSync,
} from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const repoRoot = join(dirname(fileURLToPath(import.meta.url)), '..');
const rulesDir = join(repoRoot, 'rules');
const steeringDir = join(repoRoot, '.kiro', 'steering');

// Preferred reading order; any rules file not listed is appended alphabetically.
const ORDER = [
  'product.md',
  'tech.md',
  'structure.md',
  'code-style.md',
  'serverless-only.md',
  'no-sms-no-phone-auth.md',
  'no-fallbacks-no-legacy.md',
  'dry-reuse-no-duplication.md',
  'discovery-dna-vibe-over-convenience.md',
  'honest-presence.md',
  'map-carousel.md',
  'constellation-mode.md',
];

const PROJECT_INTRO =
  '# Area Code project rules\n\n' +
  'Area Code: map-first social discovery app for South African cities ' +
  '(Johannesburg, Cape Town, Durban). Users check in at venues, earn rewards, ' +
  'and see live activity on a map. Live at areacode.co.za.\n\n' +
  'These rules are the single source of truth in `rules/`. This file is a ' +
  'generated mirror so this tool picks them up. Edit the files in `rules/`, ' +
  'then run `pnpm sync:rules`. Do not edit this file by hand.\n\n';

const BANNER_LINES = [
  'GENERATED FILE. DO NOT EDIT.',
  'Single source of truth: rules/*.md',
  'Regenerate with: pnpm sync:rules',
];
const htmlBanner = `<!-- ${BANNER_LINES.join('\n     ')} -->\n`;

function ruleFiles() {
  const present = readdirSync(rulesDir).filter((f) => f.endsWith('.md'));
  const ordered = ORDER.filter((f) => present.includes(f));
  const extras = present.filter((f) => !ORDER.includes(f)).sort();
  return [...ordered, ...extras];
}

function read(file) {
  return readFileSync(join(rulesDir, file), 'utf8').trimEnd();
}

function combinedBody(files) {
  const sections = files.map(
    (f) => `<!-- source: rules/${f} -->\n\n${read(f)}`,
  );
  return sections.join('\n\n---\n\n') + '\n';
}

// Build the full target list (path + content) for the given rule files.
function buildTargets(files) {
  const targets = [];

  // Kiro: one generated steering file per rule, content verbatim + banner.
  for (const f of files) {
    targets.push({
      path: join(steeringDir, f),
      content: `${htmlBanner}\n${read(f)}\n`,
    });
  }

  // Claude Code: index that @imports the neutral source (no copied content).
  const imports = files.map((f) => `@rules/${f}`).join('\n');
  targets.push({
    path: join(repoRoot, 'CLAUDE.md'),
    content:
      PROJECT_INTRO +
      'The lines below use Claude Code `@import` syntax to pull the canonical ' +
      'rules into context, with no duplicated copy to drift.\n\n' +
      imports +
      '\n',
  });

  const combined = htmlBanner + '\n' + PROJECT_INTRO + combinedBody(files);

  // Cursor: project rule, always applied.
  targets.push({
    path: join(repoRoot, '.cursor', 'rules', 'area-code.mdc'),
    content:
      '---\n' +
      'description: Area Code project rules (generated from rules/)\n' +
      'globs:\n' +
      'alwaysApply: true\n' +
      '---\n\n' +
      combined,
  });

  // Windsurf: always-on workspace rule.
  targets.push({
    path: join(repoRoot, '.windsurf', 'rules', 'area-code.md'),
    content: '---\ntrigger: always_on\n---\n\n' + combined,
  });

  // GitHub Copilot: repository custom instructions, always injected.
  targets.push({
    path: join(repoRoot, '.github', 'copilot-instructions.md'),
    content: combined,
  });

  return targets;
}

// Steering files we no longer own (a rule was renamed/removed) must be deleted
// so Kiro never serves a stale copy. Only touches generated steering markdown.
function staleSteering(files) {
  if (!existsSync(steeringDir)) return [];
  const want = new Set(files);
  return readdirSync(steeringDir)
    .filter((f) => f.endsWith('.md') && !want.has(f))
    .map((f) => join(steeringDir, f));
}

const check = process.argv.includes('--check');
const files = ruleFiles();
const targets = buildTargets(files);
const orphans = staleSteering(files);
let stale = false;

for (const t of targets) {
  const current = existsSync(t.path) ? readFileSync(t.path, 'utf8') : null;
  if (current === t.content) continue;
  if (check) {
    stale = true;
    console.error(`Out of sync: ${t.path.replace(repoRoot, '.')}`);
    continue;
  }
  mkdirSync(dirname(t.path), { recursive: true });
  writeFileSync(t.path, t.content);
  console.log(`Wrote ${t.path.replace(repoRoot, '.')}`);
}

for (const o of orphans) {
  if (check) {
    stale = true;
    console.error(`Stale steering file: ${o.replace(repoRoot, '.')}`);
    continue;
  }
  rmSync(o);
  console.log(`Removed ${o.replace(repoRoot, '.')}`);
}

if (check && stale) {
  console.error('\nAI rule files are stale. Run: pnpm sync:rules');
  process.exit(1);
}
if (check) console.log('AI rule files are in sync.');
